query:
DESCRIBE financial_responsible_users;
SELECT * FROM financial_responsible_users LIMIT 10;
SELECT u.id, u.name, u.role, u.email FROM users u
JOIN user_unit_permissions uup ON uup.user_id = u.id
WHERE uup.unit_id = 210001 AND u.role = 'responsavel_financeiro'
LIMIT 10;

